import { useEffect, useRef } from "react";
import {
  Engine,
  Scene,
  ArcRotateCamera,
  Vector3,
  HemisphericLight,
  MeshBuilder,
  Color3
} from "@babylonjs/core";

import { Shape } from "../types/Shape";

interface Props {
  shape: Shape;
}

function BabylonViewer({ shape }: Props) {

  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {

    if (!canvasRef.current) return;

    const engine = new Engine(canvasRef.current, true);
    const scene = new Scene(engine);

    // Camera
    const camera = new ArcRotateCamera(
      "camera",
      Math.PI / 2,
      Math.PI / 3,
      8,
      Vector3.Zero(),
      scene
    );

    camera.attachControl(canvasRef.current, true);

    // Light
    new HemisphericLight("light", new Vector3(1, 1, 0), scene);

    // Color mapping
    const getColor = (color: string) => {
      switch (color) {
        case "Red":
          return new Color3(1, 0, 0);
        case "Green":
          return new Color3(0, 1, 0);
        case "Blue":
          return new Color3(0, 0, 1);
        default:
          return new Color3(1, 1, 1);
      }
    };

    let mesh: any;

    const createShape = () => {

      if (mesh) {
        mesh.dispose();
      }

      const size = shape.size;

      switch (shape.shape) {

        case "Box":
          mesh = MeshBuilder.CreateBox("box", { size }, scene);
          break;

        case "Sphere":
          mesh = MeshBuilder.CreateSphere("sphere", {
            diameter: size
          }, scene);
          break;

        case "Cylinder":
          mesh = MeshBuilder.CreateCylinder("cyl", {
            height: size,
            diameter: size / 1.5
          }, scene);
          break;

        default:
          break;

      }

      if (mesh) {
        mesh.material = new (require("@babylonjs/core").StandardMaterial)(
          "mat",
          scene
        );
        mesh.material.diffuseColor = getColor(shape.color);
      }

    };

    createShape();

    engine.runRenderLoop(() => {
      scene.render();
    });

    window.addEventListener("resize", () => {
      engine.resize();
    });

    return () => {
      engine.dispose();
    };

  }, [shape]);

  return (
    <canvas
      ref={canvasRef}
      style={{
        width: "100%",
        height: "400px",
        border: "1px solid #ccc",
        marginTop: 20
      }}
    />
  );

}

export default BabylonViewer;
